text:
{
  "from": "TLDR AI <dan@tldrnewsletter.com>",
  "reportTitle": "Tổng hợp tin tức AI",
  "sections": [
    {
      "articles": [
        {
          "headline": "Google cập nhật Gemini",
          "link": "https://blog.google/products/gemini/gemini-collaboration-features/?utm_source=tldrai",
          "source": "Google",
          "summary": "Google đã phát hành một số tính năng chính như Canvas, Audio overview và trợ lý coding cho ứng dụng Gemini và trình duyệt web. (Đọc 3 phút)"
        },
        {
          "headline": "Roblox ra mắt hệ thống AI tạo mẫu 3D",
          "link": "https://corp.roblox.com/newsroom/2025/03/introducing-roblox-cube?utm_source=tldrai",
          "source": "Roblox",
          "summary": "Roblox giới thiệu Cube, hệ thống AI tạo sinh cho việc tạo mẫu 3D và 4D. Bản beta của Cube sẽ được tích hợp vào Roblox Studio và dưới dạng API Lua. (Đọc 15 phút)"
        },
        {
          "headline": "AI Search đang dần thay thế 'mười liên kết xanh' của Google",
          "link": "https://www.theverge.com/ai-artificial-intelligence/631352/ai-search-adobe-analytics-google-perplexity-openai?utm_source=tldrai",
          "source": "The Verge",
          "summary": "Adobe báo cáo mức tăng 1.300% lượt giới thiệu tìm kiếm từ AI cho các nhà bán lẻ trong mùa lễ năm 2024, cho thấy sự thay đổi từ các công cụ tìm kiếm truyền thống. Số liệu tương tác cho thấy người dùng từ tìm kiếm AI ở lại lâu hơn và ít thoát hơn so với người dùng giới thiệu truyền thống. (Đọc 4 phút)"
        }
      ],
      "title": "Tiêu đề và Ra mắt"
    },
    {
      "articles": [
        {
          "headline": "Smoldocling",
          "link": "https://arxiv.org/abs/2503.11576?utm_source=tldrai",
          "source": "arXiv",
          "summary": "Một mô hình mới, cực kỳ nhỏ, hiện đại để nhận dạng ký tự quang học (OCR) tài liệu. Nó có thể chạy nhanh như chớp và có độ chính xác đủ cho nhiều tác vụ xử lý tài liệu. (Đọc 13 phút)"
        },
        {
          "headline": "RewordBench",
          "link": "https://arxiv.org/abs/2503.11751?utm_source=tldrai",
          "source": "arXiv",
          "summary": "Công trình này cho thấy rằng nhiều mô hình phần thưởng phổ biến rất dễ bị thay đổi cách diễn đạt cơ bản của các lời nhắc. Nó bao gồm một tiêu chuẩn và một chiến lược tiềm năng để làm cho các mô hình phần thưởng mạnh mẽ hơn. (Đọc 21 phút)"
        },
        {
          "headline": "Tái tạo cảnh 3D từ một hình ảnh đơn lẻ",
          "link": "https://ai-kunkun.github.io/Niagara_page/?utm_source=tldrai",
          "source": "ai-kunkun",
          "summary": "Niagara giới thiệu một framework mới để tái tạo các cảnh 3D ngoài trời từ một hình ảnh duy nhất, kết hợp ước tính độ sâu và pháp tuyến với trường affine hình học và giải mã Gaussian 3D. (Đọc 3 phút)"
        }
      ],
      "title": "Nghiên cứu và Đổi mới"
    },
    {
      "articles": [
        {
          "headline": "Ổn định Camera Ảo",
          "link": "https://github.com/Stability-AI/stable-virtual-camera?utm_source=tldrai",
          "source": "Stability AI",
          "summary": "Stability AI đã phát hành một hệ thống camera đa chế độ xem tuyệt vời cho phép tổng hợp chế độ xem mới. Nó mạnh mẽ, không thương mại và chưa phải là hiện đại, nhưng nó chạy nhanh chỉ trong hai lượt chuyển tiếp. (Github)"
        },
        {
          "headline": "Điều khiển Zero-shot cho việc tạo cảnh 3D/4D",
          "link": "https://byeongjun-park.github.io/SteerX/?utm_source=tldrai",
          "source": "byeongjun-park.github.io",
          "summary": "SteerX đã đề xuất một phương pháp suy luận zero-shot để cải thiện sự liên kết hình học trong việc tạo cảnh 3D/4D bằng cách sử dụng các mô hình tái tạo chuyển tiếp không có tư thế và các hàm phần thưởng hình học. (Đọc 2 phút)"
        },
        {
          "headline": "Mô hình ngôn ngữ thị giác lai",
          "link": "https://github.com/hustvl/MaTVLM?utm_source=tldrai",
          "source": "GitHub",
          "summary": "MaTVLM là một mô hình ngôn ngữ thị giác lai tích hợp các lớp Mamba-2 vào một VLM được đào tạo trước, cải thiện tốc độ hội tụ và hiệu suất. (Github)"
        }
      ],
      "title": "Kỹ thuật và Tài nguyên"
    },
    {
      "articles": [
        {
          "headline": "Cá nhân hóa mọi thứ",
          "link": "https://fenghora.github.io/Personalize-Anything-Page/?utm_source=tldrai",
          "source": "fenghora.github.io",
          "summary": "Bạn có thể cá nhân hóa hầu hết mọi hình ảnh mà không cần tinh chỉnh hoặc đào tạo thêm bằng cách sử dụng thay thế token trong Bộ chuyển đổi khuếch tán. (Đọc 25 phút)"
        },
        {
          "headline": "Đào tạo XGB trong Trình duyệt",
          "link": "https://www.xgblog.ai/p/trainxgb-train-xgboost-in-browser?utm_source=tldrai",
          "source": "xgblog.ai",
          "summary": "Bài đăng trên blog này mô tả cách xây dựng một hệ thống đào tạo dựa trên trình duyệt được tăng tốc bởi WASM. (Đọc 8 phút)"
        },
        {
          "headline": "AI robot mới của Google có thể gấp origiami và đóng túi khóa kéo",
          "link": "https://arstechnica.com/ai/2025/03/googles-origami-folding-ai-brain-may-power-new-wave-of-humanoid-robots/?utm_source=tldrai",
          "source": "Ars Technica",
          "summary": "Google DeepMind đã tiết lộ Gemini Robotics và Gemini Robotics-ER, các mô hình AI nâng cao kỹ năng vận động tinh và khả năng thích ứng của robot cho các ứng dụng trong thế giới thực. Gemini Robotics tích hợp các khả năng về thị giác, ngôn ngữ và hành động, cho phép robot thực hiện các tác vụ phức tạp như gấp giấy origami. (Đọc 6 phút)"
        }
      ],
      "title": "Khác"
    },
    {
      "articles": [
        {
          "headline": "Google và NVIDIA mở rộng hợp tác AI",
          "link": "https://blog.google/technology/ai/google-nvidia-gtc-ai/?utm_source=tldrai",
          "source": "Google",
          "summary": "Google đã công bố sự hợp tác mở rộng với NVIDIA tại NVIDIA GTC, tập trung vào cơ sở hạ tầng AI, tối ưu hóa phần cứng và các ứng dụng trong các lĩnh vực như chăm sóc sức khỏe, năng lượng và robot. (Đọc 4 phút)"
        },
        {
          "headline": "NVIDIA thắng cuộc đua AI, nhưng suy luận vẫn là cuộc chơi của bất kỳ ai",
          "link": "https://www.theregister.com/2025/03/12/training_inference_shift/?utm_source=tldrai",
          "source": "The Register",
          "summary": "Nvidia hiện thống trị việc đào tạo AI, nhưng thị trường suy luận vẫn còn mở cho sự cạnh tranh. (Đọc 6 phút)"
        },
        {
          "headline": "Google đang chơi đuổi kịp AI Search và hình thành mối quan hệ với Chatbots",
          "link": "https://www.technologyreview.com/2025/03/17/1113264/the-download-google-playing-ai-search-catchup-and-forming-relationships-with-chatbots/?utm_source=tldrai",
          "source": "Technology Review",
          "summary": "Google đang thêm các tính năng AI mới từ Gemini vào tìm kiếm của mình, nhưng điều này được xem là đuổi kịp ChatGPT của OpenAI. (Đọc 6 phút)"
        }
      ],
      "title": "Liên kết nhanh"
    }
  ]
}
